  category_order = '["Deterjan Grubu", "Plastik Çöp Kovası Grubu", "Sıvı Aparatı Grubu", "Konteynır Grubu", "Tuvalet Kağıt Havlu Aparatı", "Medikal Eldivenler", "Balins &amp; Bemol &amp; Deox", "Cortex", "Z Katlamalı Tuvalet Kağıdı"]'
